#!/usr/bin/env bash
# ci_pull.sh — conflict-safe git pull for CI.
#
# docs/leaderboard/ and docs/leaderboards/ are always regenerated by
# `stellcoilbench update-db`, so merge conflicts in those paths are
# meaningless.  This script discards local copies of generated docs
# before pulling so conflicts never arise.
#
# Usage (from workflow steps):
#   bash tools/ci_pull.sh                    # defaults to --rebase
#   bash tools/ci_pull.sh --no-rebase        # plain merge pull
set -euo pipefail

REBASE=true
[[ "${1:-}" == "--no-rebase" ]] && REBASE=false

# Only leaderboard.rst is tracked; docs/leaderboard.json, docs/leaderboard/*.rst
# and docs/leaderboards/*.md are gitignored (generated at build time).
DOCS_GENERATED=(
  docs/leaderboard.rst
)

# Discard local changes to generated docs so they can't conflict.
git checkout -- "${DOCS_GENERATED[@]}" 2>/dev/null || true

if $REBASE; then
  git pull --rebase origin main \
    || { git rebase --abort 2>/dev/null || true; git pull origin main --no-edit; }
else
  git pull origin main --no-edit
fi
